import 'dart:convert';import 'package:http/http.dart' as http;import '../core/app_config.dart';
class ApiClient{ApiClient({http.Client? client}):_client=client??http.Client();final http.Client _client;String? token;Map<String,String> get _headers=>{'content-type':'application/json','accept':'application/json',if(token!=null)'authorization':'Bearer $token'};Future<Map<String,dynamic>> get(String p)async=>_decode(await _client.get(Uri.parse('${AppConfig.apiBaseUrl}$p'),headers:_headers).timeout(AppConfig.requestTimeout));Future<Map<String,dynamic>> post(String p,Map<String,dynamic>b)async=>_decode(await _client.post(Uri.parse('${AppConfig.apiBaseUrl}$p'),headers:_headers,body:jsonEncode(b)).timeout(AppConfig.requestTimeout));Map<String,dynamic> _decode(http.Response r){final x=r.body.isEmpty?<String,dynamic>{}:jsonDecode(r.body) as Map<String,dynamic>;if(r.statusCode<200||r.statusCode>=300)throw Exception(x['error']??x['message']??'Request failed');return x;}}
